import{v as s,g as o}from"./vendor-BkFxWNpJ.js";const c=[{id:"questdb-auth-bypass",title:"QuestDB 认证绕过与潜在 SQL 注入风险综合技术研究",date:"2026-02-14",excerpt:"深入分析 QuestDB 时序数据库的认证绕过漏洞，探讨 http.security=true 配置失效的根因，并通过 Go 编写的 PoC 程序系统验证攻击面。",content:"QuestDB 是一个开源的高性能时序数据库，广泛用于金融服务、物联网、监控和实时分析等领域。本文详细分析了 QuestDB 的认证绕过漏洞——尽管在 server.conf 中配置了 http.security=true 等安全指令，HTTP 端点依然接受所有请求，完全未进行凭证验证。文章涵盖了漏洞描述、根本原因分析、SQL 注入测试、攻击场景、PoC 验证程序、影响与风险分析以及修复建议。",tags:["QuestDB","认证绕过","SQL注入","Go","PoC"],readTime:"15 min",author:"钟智强"},{id:"kuaishou-api-key-exposure",title:"快手 Android 应用 API 密钥泄露分析",date:"2025-04-30",excerpt:"通过对快手 Android 应用的逆向分析，发现百度地图、高德地图、OPPO卡券服务等多个敏感 API 密钥泄露，评估服务滥用和数据安全风险。",content:"对快手 Android APK 进行逆向工程分析，提取并识别了多个第三方服务的 API 密钥，包括百度地图 SDK、高德地图 SDK、OPPO 卡券服务等。这些密钥泄露可能导致服务被滥用、配额被消耗以及潜在的数据安全风险。文章详细记录了逆向分析过程、发现的密钥类型、影响评估以及负责任的漏洞披露流程。",tags:["Android","逆向工程","API密钥","快手"],readTime:"10 min",author:"钟智强"},{id:"myjpj-security-audit",title:"MYJPJ 移动应用安全审计：从日志泄露到 PDPA 违规",date:"2025-03-24",excerpt:"马来西亚陆路交通局官方应用 MYJPJ 通过 Flutter 框架开发，日志中暴露了大量敏感个人信息，包括身份证号、车牌、地址、API 凭证等，严重违反 PDPA 2010。",content:"MYJPJ 是马来西亚陆路交通局(JPJ)的官方移动应用，基于 Flutter 框架开发。通过 adb logcat 日志分析发现，开发团队直接将用户的敏感个人信息打印到控制台日志中，包括但不限于：用户身份证号码、车牌号码、完整的家庭住址信息、个人联系方式、API 访问密钥和认证 Token、Bearer Token 等授权信息。这些数据暴露违反了 PDPA 2010 的多项原则。文章涵盖了完整的技术证据链分析、个人信息暴露矩阵、PDPA 违规总结以及安全加固方案。",tags:["Flutter","PDPA","数据泄露","马来西亚","CNVD"],readTime:"20 min",author:"钟智强"},{id:"etsy-phishing-counter",title:"社会工程学反制：Etsy 钓鱼网站瓦解实录",date:"2025-04-01",excerpt:"攻击者通过伪造 Etsy 支付验证页面进行钓鱼攻击，通过社会工程学方法成功反制，最终导致攻击者关闭钓鱼网站。",content:"本案例展示了社会工程学在网络安全防护中的独特价值。通过精准把握攻击者心理，成功瓦解了一个正在运行的 Etsy 钓鱼网站（域名 etsy.giving），避免了更多用户受害。文章详细记录了情报收集、DNS 分析、心理反制对话以及最终成功瓦解的全过程。",tags:["社会工程学","钓鱼反制","Etsy"],readTime:"8 min",author:"钟智强"},{id:"plugshare-aws-stripe-leak",title:"PlugShare AWS Cognito 与 Stripe 密钥泄露分析",date:"2025-03-27",excerpt:"PlugShare 应用中发现 AWS Cognito 凭证、Stripe 支付密钥等多个敏感配置信息泄露，可能导致账户接管和支付欺诈风险。",content:"通过对 PlugShare 应用的安全审计，发现多个云服务凭证泄露，包括 AWS Cognito 用户池凭证和 Stripe 支付 API 密钥。这些凭证泄露可能导致攻击者接管用户账户、发起支付欺诈以及访问后端 AWS 资源。文章详细分析了泄露路径、影响评估和修复建议。",tags:["AWS","Stripe","密钥泄露","PlugShare"],readTime:"12 min",author:"钟智强"},{id:"cyart-env-exposure",title:"Cyart.net .env 配置文件泄露：从信息收集到系统接管",date:"2025-03-31",excerpt:"Cyart.net 的 .env 配置文件未受保护，包含数据库连接信息、邮件服务器凭据、Redis 配置等，攻击者可直接接管系统。",content:"通过对 Cyart.net Web 应用的安全测试，发现 .env 配置文件直接暴露在公网。该文件包含 MySQL 数据库连接凭证、SMTP 邮件服务器配置、Redis 缓存配置、第三方 API 密钥等敏感信息。攻击者可以利用这些信息直接访问数据库、发送钓鱼邮件、甚至完全接管服务器。文章记录了从信息收集到漏洞验证的完整流程。",tags:[".env","配置泄露","Laravel","CNVD"],readTime:"10 min",author:"钟智强"},{id:"awsgatekeeper-architecture",title:"AWSGateKeeper 架构设计：打通 AWS 安全数据孤岛的统一治理实践",date:"2026-07-01",excerpt:"深入解析 AWSGateKeeper 的事件驱动架构设计，如何将 GuardDuty、Inspector、Security Hub 与 SageMaker 的安全数据横向关联为完整攻击链，将 MTTD/MTTR 从数小时压缩至 15 分钟以内。",content:`AWSGateKeeper 是一个 AWS 原生安全统一治理平台，旨在解决企业在多账户、多区域 AWS 环境中面临的安全数据孤岛问题。传统的 AWS 安全运营中，GuardDuty 负责威胁检测、Inspector 负责漏洞扫描、Security Hub 负责合规基线、Config 负责配置漂移监控，但这些服务各自为政，安全团队需要在多个控制台之间切换，无法快速关联一个完整的攻击链。

AWSGateKeeper 的核心架构基于事件驱动设计（Event-Driven Architecture），通过 EventBridge 统一接收来自各安全服务的事件流，经过自研的关联引擎进行横向分析。例如，当 GuardDuty 检测到一个可疑的 API 调用（如 iam:CreateAccessKey），关联引擎会自动查询 CloudTrail 日志确认操作者身份，检查 Inspector 是否报告过该实例的已知漏洞，并在 Security Hub 中标记相关的合规偏差。这种横向关联能力使得安全事件的平均检测与响应时间（MTTD/MTTR）从传统的数小时压缩至 15 分钟以内，告警误报率降低 60%。

在 IAM 治理方面，AWSGateKeeper 开发了基于 CloudTrail 日志分析与 iam:SimulatePrincipalPolicy API 的自动化审计引擎。该引擎通过分析过去 90 天的 API 调用日志，精准识别从未使用过的权限（僵尸权限）和超出实际需求的越权配置，自动生成最小化策略推荐。在生产环境中，该引擎将 IAM 合规率从不足 60% 提升至 98% 以上，每年减少人工审计成本约 200 工时。

此外，AWSGateKeeper 首创了面向 Amazon SageMaker AI/ML 工作负载的专项安全治理模块，实现推理端点与模型注册表的精细访问控制与 VPC 内网强制隔离，使 ML 工作负载权限违规事件降至零，填补了企业 AI 治理的空白。该项目累计下载 290 次（v1.0.0），与 AWSight 形成静态校验与动态治理闭环，整体安全运营效率提升 70% 以上。`,tags:["AWS","GuardDuty","IAM","SageMaker","安全治理","Go"],readTime:"25 min",author:"钟智强"},{id:"rust-assembly-telemetry",title:"小辣椒：Rust + x86_64 Assembly 构建零内存安全漏洞的高性能网络遥测引擎",date:"2026-06-15",excerpt:"探索在 Rust 环境下集成 x86_64 汇编互操作（Assembly Interop）对核心数据校验路径进行指令级优化，结合 Tokio 异步 IO 实现大规模并发网络遥测。",content:`小辣椒（XiaoLaJiao）是一款使用 Rust（Tokio）与 x86_64 Assembly 开发的高性能网络安全遥测工具，旨在解决复杂网络环境下协议解析在高并发时的内存安全风险与处理延迟痛点。

在传统的网络遥测工具中，协议解析通常是性能瓶颈所在。C/C++ 实现虽然性能优异，但面临缓冲区溢出、Use-After-Free 等内存安全风险；纯 Rust 实现虽然内存安全，但在某些热路径上的性能仍有优化空间。小辣椒的核心创新在于：在 Rust 的安全保证框架内，通过 Assembly Interop 对关键数据校验与提取路径进行指令级优化。

具体实现上，我们使用 Rust 的 global_asm! 和 extern "C" FFI 机制，将协议头部校验、CRC 计算、字节序转换等高频操作下沉到手写的 x86_64 汇编中。这些汇编函数利用 SIMD 指令集（SSE4.2/AVX2）进行批量数据处理，单次调用可处理 32 字节对齐的数据块，相比纯 Rust 实现提升了 3-5 倍的吞吐量。

在并发模型上，小辣椒基于 Tokio 异步运行时构建了多层事件驱动架构：底层使用 io_uring（Linux）或 kqueue（macOS）进行零拷贝数据包捕获，中间层通过 tokio::sync::mpsc 通道将原始数据包分发到多个解析 Worker，上层通过 tokio::select! 实现多协议并行解析。这种架构在保障零内存安全漏洞的前提下，单核吞吐量达到 2.8 Gbps，端到端处理延迟低于 50 微秒。`,tags:["Rust","Assembly","Tokio","网络安全","高性能","SIMD"],readTime:"20 min",author:"钟智强"},{id:"nezha-cyber-llm-pentest",title:"哪吒安全分析器：基于大语言模型 Function Calling 的智能渗透测试编排",date:"2026-05-20",excerpt:"探索 AI Agent 在自动化渗透测试场景下的落地实践——如何让 DeepSeek 大模型自主规划攻击路径、调用 nmap/sqlmap/nuclei/ffuf 并串联执行。",content:`哪吒安全分析器（NezhaSec）是一款基于 Go 语言开发的前沿安全工具，旨在探索 AI Agent 在自动化渗透测试场景下的落地可能。前端基于 Bubble Tea 框架构建了现代化的终端用户界面（TUI），核心创新点在于集成了 DeepSeek 大模型最新的 Function Calling 能力。

传统的渗透测试流程中，安全测试人员需要手动执行一系列工具：先用 nmap 扫描端口和服务，根据结果判断是否需要用 sqlmap 测试注入点，再用 nuclei 扫描已知漏洞模板，最后用 ffuf 进行目录爆破。这个过程不仅耗时，还高度依赖测试人员的经验判断。

NezhaSec 的智能体（Agent）改变了这一范式。安全测试人员仅需输入目标域名或 IP 地址，内置的 AI Agent 会自动规划攻击路径与测试步骤。它会自主判断何时需要调用 nmap 进行端口扫描、何时触发 sqlmap 检测注入点、何时利用 nuclei 扫描漏洞模板、或是调用 ffuf 进行目录爆破，并按逻辑顺序串联执行这些外部工具。

在技术实现上，NezhaSec 定义了一套标准化的 Tool Schema，每个外部工具被封装为一个 Function Definition，包含参数描述、输入验证规则和输出解析器。当 DeepSeek 模型返回 Function Call 请求时，NezhaSec 的执行引擎会验证参数合法性、启动子进程执行工具、捕获标准输出和错误输出，并将结构化结果反馈给模型进行下一步决策。

整个系统采用状态机模式管理会话生命周期，支持多轮对话上下文保持、工具执行超时控制、以及基于风险评分的自动化报告生成。目标是打造一个能够理解复杂渗透测试上下文、自主决策并执行任务的下一代红队作战辅助平台。`,tags:["AI Agent","LLM","Function Calling","DeepSeek","渗透测试","Go"],readTime:"18 min",author:"钟智强"},{id:"malaysian-osint-anti-fraud",title:"MalaysianOSINT：面向马来西亚执法场景的本土化反诈情报聚合服务",date:"2026-01-10",excerpt:"基于 C 语言与 GNU libmicrohttpd 构建的轻量级 OSINT 查询服务，对接 PDRM Semak Mule、移民局 SSPI、联邦法院电子档案等多源异构数据，单次查询端到端响应 80ms 以内。",content:`MalaysianOSINT 是一款专为马来西亚本地执法辅助、社会工程学调查与反诈骗场景量身打造的高性能轻量级情报查询服务。该服务采用 C 语言编写，基于 GNU libmicrohttpd 构建嵌入式 HTTP 服务器，资源占用极低，可在配置不足 64MB 内存的 Linux 边缘计算节点上稳定运行。

系统核心实现了对马来西亚皇家警察（PDRM）Semak Mule 反诈 API、移民局 SSPI 护照核查系统以及马来西亚联邦法院电子档案系统等多个异构公开数据源的统一封装与并发调度。针对各上游 API 响应格式不一、网络抖动频繁的痛点，设计了一套基于内存哈希表的缓存策略与带有指数退避的重试机制。

在性能优化方面，MalaysianOSINT 采用了多项工程手段：首先，使用 epoll 事件驱动模型替代传统的 select/poll，支持高并发连接；其次，对上游 API 的 JSON 响应使用自研的零拷贝解析器，避免不必要的内存分配；最后，通过连接池复用 HTTP 长连接，减少 TCP 握手开销。这些优化使得单次多源综合查询的端到端响应时间被稳定控制在 80 毫秒以内，并发查询能力超过 200 QPS。

该工具输出的结构化 JSON 数据已被部分民间反诈组织与私家侦探采纳，用于辅助识别诈骗电话号码、验证嫌疑人身份真伪以及关联分析犯罪网络。在实际案例中，MalaysianOSINT 帮助一个反诈志愿者团队在 48 小时内识别并标记了超过 300 个可疑银行账户，为警方后续的冻结行动提供了关键情报支持。`,tags:["OSINT","C语言","反诈骗","马来西亚","PDRM","情报分析"],readTime:"15 min",author:"钟智强"},{id:"redrtc-webrtc-signaling",title:"RedRTC：从零实现纯 C 语言 WebRTC 信令服务器——RFC 6455 与 epoll 的极致实践",date:"2025-10-15",excerpt:"完全从零编写、无第三方重型库依赖的 WebRTC 信令服务器，手动解析 WebSocket 协议帧，静态编译后二进制 <200KB，运行时内存 <15MB，单核支撑 10,000+ 并发连接。",content:`RedRTC 是一个完全从零开始编写、无任何第三方重型库依赖的高性能 WebRTC 信令服务器。为了追求极致的性能与可移植性，选择使用纯 C 语言实现，手动解析 WebSocket 协议帧（符合 RFC 6455 规范），并基于 epoll 事件驱动模型构建了单线程异步 I/O 事件循环。

在 WebSocket 协议实现层面，RedRTC 完整实现了 RFC 6455 规范中的帧解析逻辑，包括：FIN 位与 opcode 解析、掩码（Masking）处理、分片（Fragmentation）重组、Ping/Pong 心跳机制、以及 Close 帧的优雅关闭流程。所有帧解析操作均在栈上完成，避免了堆内存分配带来的碎片化问题。

在 I/O 模型上，RedRTC 采用 epoll（Linux）的边缘触发（Edge-Triggered）模式，配合非阻塞 Socket 和自定义的环形缓冲区（Ring Buffer），实现了高效的事件驱动循环。每个连接的读写缓冲区大小固定为 4KB，通过精细的内存池管理，即使在 10,000 个并发连接的场景下，总内存占用也不超过 50MB。

这种精简的设计使得 RedRTC 的内存占用极低，静态编译后二进制文件小于 200KB，运行时内存开销通常低于 15MB，非常适合部署在 OpenWrt 路由器、树莓派等资源受限的物联网网关设备中。在业务逻辑上，RedRTC 实现了完整的信令房间管理机制，支持创建、加入、离开房间，并精确控制每个房间的最大参与者数量为 6 人，能够高效中转 SDP Offer/Answer 与 ICE Candidate 数据。`,tags:["WebRTC","C语言","RFC 6455","epoll","IoT","嵌入式"],readTime:"22 min",author:"钟智强"},{id:"mouniu-quantitative-finance",title:"牟牛：Go + QuestDB 构建高性能量化金融数据采集与流式指标计算引擎",date:"2026-03-01",excerpt:"面向 A 股、港股、美股的高频实时数据采集系统，利用 QuestDB 列式存储与 SIMD 向量化实现亚秒级时间窗口聚合，支持 MACD、RSI、布林带、TD Sequential 等十余种指标的流式计算。",content:`牟牛（MouNiu）是一个面向金融量化分析场景的高性能股票数据抓取、存储与技术指标计算一体化系统。系统后端采用 Go 语言编写，利用其原生的并发特性（Goroutine + Channel）对 A 股、港股及美股等近 20 个公开数据源进行高频实时采集与清洗。

在数据存储层，牟牛选型并深度整合了 QuestDB 时序数据库。QuestDB 专门为时序数据优化，采用列式存储格式，支持 SIMD 向量化计算，能够在单节点上实现每秒数百万行的写入吞吐量。牟牛利用 QuestDB 的 ILP（InfluxDB Line Protocol）接口进行批量写入，通过自定义的分区策略（按月分区）和索引配置，实现了对每日数千万条 Tick 级成交数据的高效写入与亚秒级时间窗口聚合查询。

在指标计算层，牟牛实现了包括平滑异同移动平均线（MACD）、布林带（Bollinger Bands）、相对强弱指数（RSI）、汤姆·狄马克神奇九转（TD Sequential）、成交量加权平均价格（VWAP）、平均真实波幅（ATR）在内的十余种经典与高级技术指标的流式计算引擎。该引擎采用滑动窗口算法，能够在数据入库的瞬间触发指标重算，并将结果实时推送至前端仪表盘，延迟控制在 100ms 以内。

系统还实现了基于 WebSocket 的实时数据推送服务，前端仪表盘可以订阅特定股票代码的实时行情与指标更新，无需轮询。整个系统在单台 4 核 8GB 的云服务器上即可稳定运行，日均处理数据量超过 5000 万条。`,tags:["Go","QuestDB","量化金融","技术指标","时序数据库","流式计算"],readTime:"20 min",author:"钟智强"},{id:"lqz-android-forensics",title:"灵取证（LQZ）：专业级 Android 电子数据取证工具的设计与实现",date:"2025-06-15",excerpt:"面向司法鉴定与企业内部调查的 Android 设备数据取证工具，支持 ADB 逻辑镜像提取、SQLite WAL 日志回滚恢复、WhatsApp/Telegram 数据库解析，输出符合电子证据规范的结构化报告。",content:`灵取证（LQZ）是一款面向司法鉴定、企业内部调查及个人数据恢复场景的专业级 Android 设备电子数据取证工具。该工具基于 Java 语言开发，通过 ADB（Android Debug Bridge）协议与 Android 设备建立底层通信链路，支持对有屏幕锁但已开启 USB 调试模式的设备进行逻辑镜像提取。

在数据提取维度上，LQZ 涵盖了通话记录（calls.db）、短信/彩信（mmssms.db）、设备联系人（contacts2.db）、Wi-Fi 连接历史（WifiConfigStore.xml）以及 WhatsApp（msgstore.db.crypt14）、Telegram（cache4.db）等主流加密社交应用在 /data/data 目录下的数据库文件。

针对 SQLite 数据库可能存在的删除记录恢复需求，LQZ 集成了基于文件空闲页（Freelist Pages）解析与 WAL（Write-Ahead Logging）日志回滚的深度数据雕刻算法。该算法首先扫描 SQLite 数据库文件的空闲页链表，提取被标记为删除但尚未被覆写的记录；然后分析 WAL 日志文件中的历史事务，通过逆向回放事务操作恢复被 DELETE 语句删除的行数据。在实际测试中，该算法对 24 小时内删除的记录恢复率达到 85% 以上。

所有提取到的数据均以结构化的 HTML 报告与加密的 ZIP 归档形式输出，报告中包含数据提取时间戳、设备信息摘要、数据完整性哈希值（SHA-256）等元数据，严格遵循电子证据的完整性与连续性原则（Chain of Custody）。LQZ 已在多个实际案件中被采用，累计获得 88 个 GitHub Stars 和 17 个 Forks。`,tags:["Android","数字取证","ADB","SQLite","Java","电子证据"],readTime:"18 min",author:"钟智强"},{id:"awsight-mobile-cloud-ops",title:"AWSight：用手机管理 AWS 云基础设施的移动端实践",date:"2026-06-01",excerpt:"基于 React Native（Expo）开发的 AWS 云端监控移动应用，支持 ECS/ECR 资源管理、安全组规则配置、IAM 角色与策略管理，内嵌 CloudShell 环境。",content:`AWSight 是一款基于 React Native（Expo）开发的移动应用，旨在解决 AWS 运维中的常见痛点：通过 CloudShell 或控制台手动配置安全组效率低、易出错，IAM 权限管理复杂且缺少便携工具。

在架构设计上，AWSight 采用了分层架构：表现层使用 React Native 组件库构建跨平台 UI，业务逻辑层封装了 AWS SDK for JavaScript v3 的核心 API 调用，数据层使用 AsyncStorage 进行本地凭证缓存（AES-256 加密）。应用支持多账户切换，通过 AWS STS AssumeRole 实现跨账户访问。

核心功能模块包括：ECS 集群与服务的实时状态监控（CPU/内存利用率、任务计数、部署状态）、ECR 镜像仓库管理（镜像列表、标签管理、漏洞扫描结果查看）、安全组规则的可视化编辑（支持入站/出站规则的增删改查，带有 CIDR 格式校验）、IAM 角色与策略的树形浏览与权限模拟（集成 iam:SimulatePrincipalPolicy）、以及内嵌的 CloudShell 终端环境（基于 WebSocket 连接 AWS CloudShell API）。

通过集成 AWS SDK 和 IAM 感知逻辑，AWSight 能自动校验权限与资源配置，在用户尝试修改安全组规则时，会预先检查当前 IAM 角色是否具有 ec2:AuthorizeSecurityGroupIngress 等必要权限，避免操作失败。这种前置校验机制显著降低了误操作风险，让工程师能够随时随地用手机处理核心云运维任务。`,tags:["AWS","React Native","Expo","云运维","移动应用","IAM"],readTime:"15 min",author:"钟智强"}];function A(){const n=o(c),a=o(""),i=o(null),u=s(()=>{const e=new Set;return n.value.forEach(t=>t.tags.forEach(r=>e.add(r))),Array.from(e)}),l=s(()=>n.value.filter(e=>{const t=!a.value||e.title.toLowerCase().includes(a.value.toLowerCase())||e.excerpt.toLowerCase().includes(a.value.toLowerCase()),r=!i.value||e.tags.includes(i.value);return t&&r}));return{allPosts:n,searchQuery:a,selectedTag:i,allTags:u,filteredPosts:l,getPostById:e=>n.value.find(t=>t.id===e)}}export{A as u};
